local StatusLabel = OptionsGroup:AddLabel("Statut : Inactif", true)

OptionsGroup:AddToggle("AutoSpawn", {
	Text     = "Création automatique",
	Default  = false,
	Callback = function(v)
		if v and not state.selectedPetLabel then
			StatusLabel:SetText("Statut : Aucun familier sélectionné.")
