			return
		end
		state.autoSpawn = v
		StatusLabel:SetText(v and "Status: Creating..." or "Statut : Inactif")
	end,
})

OptionsGroup:AddSlider("SpawnDelay", {
	Text     = "Délai de création du familier (secondes)",
